-- ============================================================
-- Fill april 2026 met bezettingsdata voor Bistro Get-Filly
-- (vervangt eerdere 7 dagen — deze is compleet)
-- ============================================================

delete from public.occupancy_days
where restaurant_id = '00000000-0000-0000-0000-000000000001'
  and date >= '2026-04-01' and date <= '2026-04-30';

-- Capaciteit: 48 stoelen. Gasten ≈ bezettings% × 48 / 100 (afgerond).
-- Patroon: wo/do rustiger, vr/za/zo druk, ma/di variabel, Koningsdag (27) extra druk.
